inline f64 fexp(f64 p) {
    // exp(x) = exp(int(x)) + exp(fract(x))
    // This allows us to do a fast integer power of e, and keeps our estimation within a small fractional range.
    i64 p_i = i64(p);
    f64 result = fipow(E, p_i);
    f64 p_f = p - p_i;
    
    f64 result_fract = 1 + p_f, x = p_f * p_f;
    // We use 64 iterations of the taylor series expansion for the fractional part:
    //      exp(x) = 1 + X + X^2/2 + X^3/6 + X^4/24 + ...
    for (i64 i = 0; i < MATH_PRECISION; i += 8) { // Loop is unrolled 8x to avoid control flow overhead / improve scheduling.
        result_fract += x * EXP_CONST[i];
        x *= p_f;
        result_fract += x * EXP_CONST[i + 1];
        x *= p_f;
        result_fract += x * EXP_CONST[i + 2];
        x *= p_f;
        result_fract += x * EXP_CONST[i + 3];
        x *= p_f;
        result_fract += x * EXP_CONST[i + 4];
        x *= p_f;
        result_fract += x * EXP_CONST[i + 5];
        x *= p_f;
        result_fract += x * EXP_CONST[i + 6];
        x *= p_f;
        result_fract += x * EXP_CONST[i + 7];
        x *= p_f;
    }
    return result * result_fract;
}

