const char* sec = nullptr;
clock_t last;
i64 n_last;

void timer(const char* str, i64 n) {
    clock_t now = clock();
    if (sec) {
        clock_t diff = now - last;
        printf("  - %s took %.3fs, %.3fns/op\n", sec, f64(diff) / CLOCKS_PER_SEC, f64(diff) * 1000000000 / CLOCKS_PER_SEC / n_last);
    }
    sec = str;
    last = now;
    n_last = n;
}

int main() {
    printf("libc pow:\n");
    timer("int/int pow", 1024 * 1024 * 1024);
    for (i64 k = 0; k < 1024; k ++) for (i64 i = 0; i < 1024; i ++) for (i64 j = 0; j < 1024; j ++) pow(INT_VALS[i], INT_POWS[j]);
    timer("float/int pow", 1024 * 1024 * 1024);
    for (i64 k = 0; k < 1024; k ++) for (i64 i = 0; i < 1024; i ++) for (i64 j = 0; j < 1024; j ++) pow(FPINT_VALS[i], FPINT_POWS[j]);
    timer("float/float pow", 1024 * 1024 * 1024);
    for (i64 k = 0; k < 1024; k ++) for (i64 i = 0; i < 1024; i ++) for (i64 j = 0; j < 1024; j ++) pow(FLOAT_VALS[i], FLOAT_POWS[j]);
    
    timer("int/int pow", 1024 * 1024 * 1024);
    printf("\nclover pow:\n");
    for (i64 k = 0; k < 1024; k ++) for (i64 i = 0; i < 1024; i ++) for (i64 j = 0; j < 1024; j ++) fpow(INT_VALS[i], INT_POWS[j]);
    timer("float/int pow", 1024 * 1024 * 1024);
    for (i64 k = 0; k < 1024; k ++) for (i64 i = 0; i < 1024; i ++) for (i64 j = 0; j < 1024; j ++) fpow(FPINT_VALS[i], FPINT_POWS[j]);
    timer("float/float pow", 1024 * 1024 * 1024);
    for (i64 k = 0; k < 1024; k ++) for (i64 i = 0; i < 1024; i ++) for (i64 j = 0; j < 1024; j ++) fpow(FLOAT_VALS[i], FLOAT_POWS[j]);
    timer("", 0);
}